CREATE TABLE IF NOT EXISTS _cf_KV ( key TEXT PRIMARY KEY, value BLOB ) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS sso_login_challenges ( id TEXT PRIMARY KEY, user_id TEXT, identity_type TEXT NOT NULL, identity_value TEXT NOT NULL, otp_code TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'pending', ip_hash TEXT, ua_hash TEXT, expires_at INTEGER NOT NULL, created_at INTEGER NOT NULL, consumed_at INTEGER );
CREATE TABLE IF NOT EXISTS sso_trusted_devices ( id TEXT PRIMARY KEY, user_id TEXT NOT NULL, device_hash TEXT NOT NULL, device_name TEXT, status TEXT NOT NULL DEFAULT 'pending', first_ip_hash TEXT, last_ip_hash TEXT, first_ua_hash TEXT, last_ua_hash TEXT, last_seen_at INTEGER, created_at INTEGER NOT NULL, updated_at INTEGER NOT NULL );
CREATE TABLE IF NOT EXISTS sso_login_events ( id TEXT PRIMARY KEY, user_id TEXT, identity_type TEXT, identity_value TEXT, flow TEXT NOT NULL, result TEXT NOT NULL, ip_hash TEXT, ua_hash TEXT, meta_json TEXT, created_at INTEGER NOT NULL );
CREATE TABLE IF NOT EXISTS sso_redirect_audit ( id TEXT PRIMARY KEY, user_id TEXT NOT NULL, chosen_role TEXT, target_url TEXT, created_at INTEGER NOT NULL );
CREATE TABLE IF NOT EXISTS auth_provider_settings ( k TEXT PRIMARY KEY, v TEXT NOT NULL, updated_at INTEGER NOT NULL );
CREATE TABLE IF NOT EXISTS sso_step_up_challenges ( id TEXT PRIMARY KEY, user_id TEXT NOT NULL, action_code TEXT NOT NULL, otp_code TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'pending', ip_hash TEXT, ua_hash TEXT, expires_at INTEGER NOT NULL, created_at INTEGER NOT NULL, consumed_at INTEGER );
CREATE TABLE IF NOT EXISTS roles ( id TEXT PRIMARY KEY, name TEXT NOT NULL UNIQUE, created_at INTEGER NOT NULL );
CREATE TABLE IF NOT EXISTS user_roles ( user_id TEXT NOT NULL, role_id TEXT NOT NULL, created_at INTEGER NOT NULL, PRIMARY KEY (user_id, role_id) );
CREATE TABLE IF NOT EXISTS users ( id TEXT PRIMARY KEY, full_name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, phone TEXT UNIQUE NOT NULL, password_hash TEXT, pin_hash TEXT, role TEXT NOT NULL DEFAULT 'talent', social_provider TEXT, social_id TEXT, status TEXT DEFAULT 'pending', created_at INTEGER NOT NULL, fail_count INTEGER DEFAULT 0, locked_until INTEGER );
CREATE TABLE IF NOT EXISTS otp_requests ( id TEXT PRIMARY KEY, identifier TEXT NOT NULL, code TEXT NOT NULL, purpose TEXT NOT NULL, expires_at INTEGER NOT NULL );
CREATE TABLE IF NOT EXISTS sessions ( id TEXT PRIMARY KEY, user_id TEXT NOT NULL, role TEXT NOT NULL, created_at INTEGER NOT NULL, expires_at INTEGER NOT NULL );
CREATE TABLE IF NOT EXISTS ip_rate_limit ( ip TEXT PRIMARY KEY, count INTEGER, expires_at INTEGER );
